VALUES
  ('social-worker-moex-02591', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '新修正的社會救助法將「中低收入戶」法制化。請問：中低收入戶的家庭所得標準為家庭總收入除以家 庭總人口，每人每月不超過最低生活費用的多少倍？', '["1.5倍", "2倍", "2.5倍", "3倍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02592', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據社會工作師法，即便通過社會工作師考試，有特殊情事，主管機關亦不得發給執業執照；已領取者， 撤銷或廢止之。請問：上述之「特殊情事」不包含下列那項陳述？', '["犯有妨害性自主罪，經有罪判決確定", "受監護或輔助宣告，尚未撤銷", "罹患精神疾病，經主管機關委請相關專科醫師認定不能執行業務", "因出境歇業，未報請主管機關備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02593', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據社會工作師法，直轄市或縣（市）社會工作師達多少人以上，可以成立該區域之社會工作師公會？', '["10人", "15人", "20人", "25人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02594', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據特殊境遇家庭扶助條例，申請緊急生活扶助金之特殊境遇家庭，原則上每人每次領取補助之期限為 多久？', '["1個月", "3個月", "6個月", "1年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02595', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '性侵害犯罪防治法設有「陪同偵訊」之規定，請問：下列那一類人員並未被允許陪同性侵害被害人偵訊？', '["被害人之親阿姨", "被害人之男朋友", "社工", "醫師"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02596', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據性別工作平等法，有關「育嬰留職停薪」之規定，下列那一項陳述正確？', '["凡受僱者任職滿1年後，於每一子女滿2歲前，得申請育嬰留職停薪", "育嬰留職停薪期間，每一子女不得逾3年", "同時撫育2名子女以上者，其育嬰留職停薪期間應分開計算", "受僱者於育嬰留職停薪期間，得繼續參加原有之社會保險，原由雇主繳納之保費免予繳納"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02597', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據全民健康保險法，被保險人區分成六大類。請問：符合社會救助法規定之低收入戶成員為第幾類被 保險人？', '["第三類", "第四類", "第五類", "第六類"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02598', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依照國民年金法第32條之1規定，被保險人分娩或早產，得請領生育給付，其給付標準如下列，請問何 者錯誤？', '["分娩者，按其月投保金額一次發給1個月生育給付", "早產者，按其月投保金額一次發給3個月生育給付", "分娩或早產為雙生以上者，比例增給", "被保險人同時符合相關社會保險生育給付或補助條件者，僅得擇一請領"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02599', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於身心障礙者遭受遺棄、虐待、限制其自由等各種行為且情況危急非立即給予保護、安置或其他處置， 其生命、身體或自由有立即之危險或有危險之虞者，依身心障礙者權益保障法第80條所示，身心障礙者 之緊急保護安置，不得超過72小時，而非72小時以上之安置，不足以保護身心障礙者時，得聲請法院 裁定繼續保護安置，期限是以多久為限？', '["1個月", "3個月", "6個月", "9個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02600', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '就兒童及少年性交易防制條例第18條所示，經法院依審理之結果，認為兒童或少年從事性交易者，法院 應裁定將其安置於中途學校，並施予多少年之特殊教育？', '["1年", "2年", "3年", "4年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
